	base: {
		ref: string;
	};
};

type GitHubApiPullRequestFile = {
	filename: string;
};

type GitHubApiPullRequestMergeResponse = {
	sha: string | null;
	merged: boolean;
	message: string;
};

export class GitHubPullRequestError extends Error {
	constructor(
		readonly status: number,
		readonly owner: string,
		readonly repository: string,
		readonly action: string,
		readonly messageText: string,
	) {
		super(
			`GitHub pull request ${action} failed for ${owner}/${repository} (${status}): ${messageText}`,
		);
		this.name = "GitHubPullRequestError";
	}
}

export async function createOrReuseOpenPullRequest(
	input: {
		owner: string;
		repository: string;
		head: string;
		base: string;
		title: string;
		body: string;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
): Promise<PullRequestSummary> {
	const existing = await findOpenPullRequestForHead({
		env,
		owner: input.owner,
		repository: input.repository,
		head: input.head,
		base: input.base,
	});

	if (existing) {
		return {
			reused: true,
			...existing,
		};
	}

	let created: Awaited<ReturnType<typeof createPullRequest>>;
	try {
		created = await createPullRequest({
			env,
			owner: input.owner,
			repository: input.repository,
			title: input.title,
			body: input.body,
			head: input.head,
			base: input.base,
		});
	} catch (error) {
		if (
			!(error instanceof GitHubPullRequestError) ||
			![409, 422].includes(error.status)
		) {
			throw error;
		}

		const racedExisting = await findOpenPullRequestForHead({
			env,
			owner: input.owner,
			repository: input.repository,
			head: input.head,
			base: input.base,
		});

		if (racedExisting) {
			return {
				reused: true,
				...racedExisting,
			};
		}

		throw error;
	}

	return {
		reused: false,
		...created,
	};
}

export async function getPullRequest(
	input: {
		owner: string;
		repository: string;
		pullRequestNumber: number;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
): Promise<PullRequestSummary> {
	const response = await fetch(
		`https://api.github.com/repos/${encodeURIComponent(input.owner)}/${encodeURIComponent(input.repository)}/pulls/${encodeURIComponent(String(input.pullRequestNumber))}`,
		{
			headers: {
				Accept: "application/vnd.github+json",
				Authorization: `Bearer ${env.GITHUB_TOKEN}`,
				"X-GitHub-Api-Version": "2022-11-28",
			},
		},
	);

	if (!response.ok) {
		const message = await safeResponseText(response);
		throw new GitHubPullRequestError(
			response.status,
			input.owner,
			input.repository,
			"lookup",
			message,
		);
	}

	const payload = normalizePullRequest(await response.json());
	return {
		reused: true,
		number: payload.number,
		htmlUrl: payload.html_url,
		title: payload.title,
		headRef: payload.head.ref,
		baseRef: payload.base.ref,
	};
}

export async function getPullRequestChangedFiles(
	input: {
		owner: string;
		repository: string;
		pullRequestNumber: number;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
): Promise<string[]> {
	const perPage = 100;
	let page = 1;
	const filenames: string[] = [];

	while (true) {
		const response = await fetch(
			`https://api.github.com/repos/${encodeURIComponent(input.owner)}/${encodeURIComponent(input.repository)}/pulls/${encodeURIComponent(String(input.pullRequestNumber))}/files?per_page=${perPage}&page=${page}`,
			{
				headers: {
					Accept: "application/vnd.github+json",
					Authorization: `Bearer ${env.GITHUB_TOKEN}`,
					"X-GitHub-Api-Version": "2022-11-28",
				},
			},
		);

		if (!response.ok) {
			const message = await safeResponseText(response);
			throw new GitHubPullRequestError(
				response.status,
				input.owner,
				input.repository,
				"list_files",
				message,
			);
		}

		const payload = normalizePullRequestFiles(await response.json());
		for (const candidate of payload) {
			filenames.push(candidate.filename);
		}

		if (payload.length < perPage) {
			return filenames;
		}

		const linkHeader = response.headers.get("link");
		if (!linkHeader || !linkHeader.includes('rel="next"')) {
			return filenames;
		}
		page += 1;
	}
}

export async function mergePullRequest(
	input: {
		owner: string;
		repository: string;
		pullRequestNumber: number;
		mergeMethod?: "merge" | "squash" | "rebase";
		commitTitle?: string;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
): Promise<PullRequestMergeResult> {
	const response = await fetch(
		`https://api.github.com/repos/${encodeURIComponent(input.owner)}/${encodeURIComponent(input.repository)}/pulls/${input.pullRequestNumber}/merge`,
		{
			method: "PUT",
			headers: {
				Accept: "application/vnd.github+json",
				Authorization: `Bearer ${env.GITHUB_TOKEN}`,
				"X-GitHub-Api-Version": "2022-11-28",
				"content-type": "application/json",
			},
			body: JSON.stringify({
				merge_method: input.mergeMethod ?? "squash",
				commit_title: input.commitTitle,
			}),
		},
	);

	if (!response.ok) {
		const message = await safeResponseText(response);
		throw new GitHubPullRequestError(
			response.status,
			input.owner,
			input.repository,
			"merge",
			message,
		);
	}

	const payload = normalizePullRequestMergeResponse(await response.json());

	return {
		number: input.pullRequestNumber,
		merged: payload.merged,
		message: payload.message,
		sha: payload.sha,
	};
}

async function findOpenPullRequestForHead({
	env,
	owner,
	repository,
	head,
	base,
}: {
	env: RhapsodyGitHubEnv;
	owner: string;
	repository: string;
	head: string;
	base: string;
}): Promise<{
	number: number;
	htmlUrl: string;
	title: string;
	headRef: string;
	baseRef: string;
} | null> {
	const response = await fetch(
		`https://api.github.com/repos/${encodeURIComponent(owner)}/${encodeURIComponent(
			repository,
	)}/pulls?state=open&head=${encodeURIComponent(`${owner}:${head}`)}`,
		{
			headers: {
				Accept: "application/vnd.github+json",
				Authorization: `Bearer ${env.GITHUB_TOKEN}`,
				"X-GitHub-Api-Version": "2022-11-28",
			},
		},
	);

	if (!response.ok) {
		const message = await safeResponseText(response);
		throw new GitHubPullRequestError(
			response.status,
			owner,
			repository,
			"lookup",
			message,
		);
	}

	const pulls = normalizePullRequestList(await response.json());

	if (pulls.length === 0) {
		return null;
	}

	const candidate = pulls.find((pull) => pull.base.ref === base);

	if (!candidate) {
		return null;
	}

	return {
		number: candidate.number,
		htmlUrl: candidate.html_url,
		title: candidate.title,
		headRef: candidate.head.ref,
		baseRef: candidate.base.ref,
	};
}

